// Parse GitHub push webhook payload
const body = $input.first().json.body || $input.first().json;

// Extract commit data
const headCommit = body.head_commit || {};
const commitMessage = headCommit.message || '';
const branch = (body.ref || '').replace('refs/heads/', '');
const commits = body.commits || [];

// Collect all changed files across commits
const allAdded = [];
const allModified = [];
const allRemoved = [];

for (const c of commits) {
  if (c.added) allAdded.push(...c.added);
  if (c.modified) allModified.push(...c.modified);
  if (c.removed) allRemoved.push(...c.removed);
}

const changedFiles = [...new Set([...allAdded, ...allModified, ...allRemoved])];

// Check for auto-status loop prevention
const isAutoStatus = commitMessage.includes('auto-status:');

return [{
  json: {
    commitMessage,
    branch,
    changedFiles,
    changedFilesList: changedFiles.join('\n'),
    isAutoStatus,
    pusher: body.pusher ? body.pusher.name : 'unknown',
    repository: body.repository ? body.repository.full_name : 'unknown',
    timestamp: headCommit.timestamp || new Date().toISOString()
  }
}];

// Decode base64 content from GitHub API responses
const jsonItem = $('Fetch project_status.json').first().json;
const mdItem = $('Fetch project_status.md').first().json;

const jsonContent = Buffer.from(jsonItem.content, 'base64').toString('utf-8');
const mdContent = Buffer.from(mdItem.content, 'base64').toString('utf-8');

const commitData = $('Parse Commit Data').first().json;

return [{
  json: {
    currentStatusJson: jsonContent,
    currentStatusMd: mdContent,
    jsonSha: jsonItem.sha,
    mdSha: mdItem.sha,
    commitMessage: commitData.commitMessage,
    changedFiles: commitData.changedFilesList,
    branch: commitData.branch,
    pusher: commitData.pusher,
    timestamp: commitData.timestamp
  }
}];

// Parse AI output and generate markdown from updated JSON
const aiOutput = $('AI: Update Status JSON').first().json;
const rawText = aiOutput.text || aiOutput.message || JSON.stringify(aiOutput);

// Clean up potential markdown fences
let cleanJson = rawText.trim();
if (cleanJson.startsWith('```')) {
  cleanJson = cleanJson.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

let statusObj;
try {
  statusObj = JSON.parse(cleanJson);
} catch (e) {
  throw new Error('AI returned invalid JSON: ' + e.message + '\n\nRaw output: ' + rawText.substring(0, 500));
}

const updatedJson = JSON.stringify(statusObj, null, 2);

// Generate markdown from the JSON
const lines = [];
lines.push('# Project Status — AutoShop SMS AI');
lines.push('');
lines.push(`> Last updated: ${statusObj.last_updated || new Date().toISOString().split('T')[0]}`);
lines.push(`> Updated by: auto-status workflow`);
lines.push('');

// Project completion
if (statusObj.project_completion_estimate) {
  lines.push(`## Project Completion Estimate: ${statusObj.project_completion_estimate}%`);
  lines.push('');
}

// Stage progress table
if (statusObj.stages) {
  lines.push('## Stage Progress');
  lines.push('');
  lines.push('| Stage | Weight | Progress | Weighted |');
  lines.push('|-------|--------|----------|----------|');
  for (const stage of statusObj.stages) {
    const weighted = ((stage.weight * stage.progress) / 100).toFixed(1);
    lines.push(`| ${stage.name} | ${stage.weight}% | ${stage.progress}% | ${weighted}% |`);
  }
  lines.push('');
}

// Current focus
if (statusObj.current_focus) {
  lines.push('## Current Focus');
  lines.push('');
  lines.push(statusObj.current_focus);
  lines.push('');
}

// Active tasks
if (statusObj.active_tasks) {
  lines.push('## Active Tasks');
  lines.push('');
  if (statusObj.active_tasks.in_progress && statusObj.active_tasks.in_progress.length > 0) {
    lines.push('### In Progress');
    for (const t of statusObj.active_tasks.in_progress) {
      lines.push(`- ${t}`);
    }
    lines.push('');
  }
  if (statusObj.active_tasks.todo && statusObj.active_tasks.todo.length > 0) {
    lines.push('### Todo');
    for (const t of statusObj.active_tasks.todo) {
      lines.push(`- ${t}`);
    }
    lines.push('');
  }
  if (statusObj.active_tasks.done && statusObj.active_tasks.done.length > 0) {
    lines.push('### Done');
    for (const t of statusObj.active_tasks.done) {
      lines.push(`- ${t}`);
    }
    lines.push('');
  }
}

// Blocked items
if (statusObj.blocked_items && statusObj.blocked_items.length > 0) {
  lines.push('## Blocked Items');
  lines.push('');
  for (const b of statusObj.blocked_items) {
    lines.push(`- **${b.item || b}**: ${b.reason || ''} (owner: ${b.owner || 'unassigned'})`);
  }
  lines.push('');
}

// Recent changes
if (statusObj.recent_changes && statusObj.recent_changes.length > 0) {
  lines.push('## Recent Changes');
  lines.push('');
  for (const c of statusObj.recent_changes) {
    if (typeof c === 'string') {
      lines.push(`- ${c}`);
    } else {
      lines.push(`- **${c.date || 'undated'}**: ${c.description || c.change || JSON.stringify(c)}`);
    }
  }
  lines.push('');
}

// Next owner decision
if (statusObj.next_owner_decision) {
  lines.push('## Next Owner Decision');
  lines.push('');
  lines.push(statusObj.next_owner_decision);
  lines.push('');
}

const updatedMd = lines.join('\n');

const mergeData = $('Merge & Decode').first().json;

return [{
  json: {
    updatedJson,
    updatedMd,
    jsonSha: mergeData.jsonSha,
    mdSha: mergeData.mdSha,
    branch: mergeData.branch
  }
}];
